# -*- coding: utf-8 -*-
import re, sqlite3

def normalize(text):
    text = re.sub(r'\s+', '', text)
    text = re.sub(r'[？?]', '？', text)
    return text.strip()

def extract_core(text):
    core = re.split(r'\s*[\(（][1１][\)）]', text)[0].strip()
    core = re.split(r'\s*[A-D][\.、]', core)[0].strip()
    return core

db_path = r'C:\\insurance_ai\\platform\\instance\\insurance_exam.db'
conn = sqlite3.connect(db_path)
cur = conn.cursor()

cur.execute("SELECT content FROM questions WHERE subject='保險法規'")
db_fagui = set(normalize(extract_core(r[0])) for r in cur.fetchall())

cur.execute("SELECT content FROM questions WHERE subject='保險實務'")
db_shiwu = set(normalize(extract_core(r[0])) for r in cur.fetchall())
conn.close()

print(f"資料庫法規: {len(db_fagui)} 題, 實務: {len(db_shiwu)} 題")

