def is_duplicate(q, db_set):
    nq = normalize(q)
    for db_q in db_set:
        if len(nq) > 10 and len(db_q) > 10:
            if nq[:15] == db_q[:15]: return True
            if nq in db_q or db_q in nq: return True
    return False

fagui_new = [q for q in fagui_pdf if not is_duplicate(q, db_fagui)]
shiwu_new = [q for q in shiwu_pdf if not is_duplicate(q, db_shiwu)]

